/**
 * MedX combobox forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Searchable supplier and warehouse combobox.
 */
const COMBOBOX_TOKENS = Object.freeze({
  primary: { value: "forms-combobox-primary", scope: "forms" },
  secondary: { value: "forms-combobox-secondary", scope: "forms" },
  muted: { value: "forms-combobox-muted", scope: "forms" },
  accent: { value: "forms-combobox-accent", scope: "forms" },
  surface: { value: "forms-combobox-surface", scope: "forms" },
});

const COMBOBOX_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const COMBOBOX_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const comboboxRegistry = new Map();
const COMBOBOX_listeners = new Set();
let COMBOBOX_seq = 0;

function createComboboxId(prefix = "medx-forms-combobox") {
  COMBOBOX_seq += 1;
  return `${prefix}-${COMBOBOX_seq}`;
}

function registerCombobox(config = {}) {
  const entryId = config.id ?? createComboboxId();
  const preset = COMBOBOX_PRESETS[config.preset ?? "default"] ?? COMBOBOX_PRESETS.default;
  const token = COMBOBOX_TOKENS[config.token ?? preset.token] ?? COMBOBOX_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: COMBOBOX_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  comboboxRegistry.set(entryId, entry);
  notifyComboboxListeners("register", entry);
  return entry;
}

function updateCombobox(id, patch = {}) {
  const entry = comboboxRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyComboboxListeners("update", entry);
  return entry;
}

function resolveCombobox(id) {
  const entry = comboboxRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listComboboxEntries(filter = {}) {
  let items = Array.from(comboboxRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onComboboxEvent(listener) {
  COMBOBOX_listeners.add(listener);
  return () => COMBOBOX_listeners.delete(listener);
}

function notifyComboboxListeners(type, entry) {
  for (const listener of COMBOBOX_listeners) {
    try {
      listener({ type, entry, registrySize: comboboxRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:combobox] listener error", err.message);
    }
  }
}

function getComboboxMetrics() {
  const items = listComboboxEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(COMBOBOX_TOKENS).length,
    presets: Object.keys(COMBOBOX_PRESETS).length,
  };
}

async function runMedxCombobox() {
  console.log("[medx:ui:forms:combobox] runtime initialized");
  console.log(`[medx:ui:forms:combobox] tokens=${Object.keys(COMBOBOX_TOKENS).length} presets=${Object.keys(COMBOBOX_PRESETS).length}`);

  const events = [];
  onComboboxEvent((e) => events.push(e.type));

  const domains = Object.keys(COMBOBOX_SUPPLY_CHAIN);
  const presets = Object.keys(COMBOBOX_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerCombobox({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/combobox" },
    });
  }

  const first = listComboboxEntries()[0];
  if (first) updateCombobox(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getComboboxMetrics();
  const resolved = first ? resolveCombobox(first.id) : null;

  console.log(`[medx:ui:forms:combobox] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:combobox] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:combobox] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:combobox] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:combobox] bootstrap complete");
}

module.exports = runMedxCombobox;
